import { useContext } from "react";
import { AuthContext } from "../AuthContext";

export default function ClubHeader({
                                       club,
                                       activeTab,
                                       membership = { isMember: false, hasPending: false, isLeader: false },
                                       leaders = [],
                                       onJoin,
                                       onLeave,
                                       onCancelRequest
                                   }) {
    const { user } = useContext(AuthContext);

    return (
        <div className="club-header">
            <div className="club-header-top">
                <div className="club-header-left">
                    <img
                        src={club.logoUrl || "/default-club.png"}
                        alt={club.name}
                        className="club-logo"
                    />

                    <div className="club-meta">
                        <h1 className="club-title">
                            {club.name}
                            {club.shortName && (
                                <span className="club-short"> {club.shortName}</span>
                            )}
                        </h1>

                        {leaders.length > 0 && (
                            <div className="club-leaders">
                                ⭐ Leader{leaders.length > 1 ? "s" : ""}: {leaders.join(", ")}
                            </div>
                        )}

                        {club.description && (
                            <div className="club-description">
                                {club.description}
                            </div>
                        )}

                        <div className="club-sub">
                            {club.website && (
                                <a href={club.website} target="_blank" rel="noreferrer">
                                    {club.website}
                                </a>
                            )}
                            {club.twitter && <span>@{club.twitter}</span>}
                            {club.country && <span>{club.country}</span>}
                        </div>
                    </div>
                </div>

                {user && (
                    <div className="club-member-pill">
                        <span className="club-member-user">
                            ⭐ {user.username}
                        </span>

                        {membership.isMember ? (
                            membership.isLeader ? (
                                <button className="pill-btn pill-disabled" disabled>
                                    Leader
                                </button>
                            ) : (
                                <button className="pill-btn pill-leave" onClick={onLeave}>
                                    Leave
                                </button>
                            )
                        ) : membership.hasPending ? (
                            <button className="pill-btn pill-pending" onClick={onCancelRequest}>
                                Pending
                            </button>
                        ) : (
                            <button className="pill-btn pill-join" onClick={onJoin}>
                                Join
                            </button>
                        )}
                    </div>
                )}
            </div>

            <div className="club-tabs">
                {["overview", "stats", "matches", "news", "members"].map(tab => (
                    <a
                        key={tab}
                        href={`#/clubs/${club.id}/${tab}`}
                        className={activeTab === tab ? "active" : ""}
                    >
                        {tab.toUpperCase()}
                    </a>
                ))}
            </div>
        </div>
    );
}
